SELECT MAX(created_at) AS latest_status_update
FROM status_updates
WHERE user_id = 1;

SELECT COUNT(*) AS public_status_count
FROM status_updates
WHERE user_id = 0 AND is_private = 0;

SELECT status_text, engagement_score
FROM status_updates
WHERE created_at = (SELECT MAX(created_at) FROM status_updates);

SELECT status_text
FROM status_updates
WHERE is_private = 0;

SELECT COUNT(user_id) AS active_users_with_status
FROM users
WHERE is_active = 1 AND user_id IN (
  SELECT user_id
  FROM status_updates
);

SELECT user_id, MAX(created_at) AS latest_status
FROM status_updates
WHERE user_id = 1;

SELECT user_id, MAX(engagement_score) AS max_engagement_score
FROM status_updates
GROUP BY user_id;
